import { type Nullable } from "../types";

/**
 * @internal
 */
export class IntersectionInfo {
    public faceId = 0;
    public subMeshId = 0;
    public _internalSubMeshId = 0;

    constructor(
        public bu: Nullable<number>,
        public bv: Nullable<number>,
        public distance: number
    ) {}
}
